from flask import Flask, request, redirect, url_for, render_template_string, session, flash
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
import qrcode
import io
import os
import secrets
from datetime import datetime, timedelta

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(16))

# Mock user database
users = {
    "admin": {
        "password_hash": generate_password_hash("password123"),
        "mfa_secret": "JBSWY3DPEHPK3PXP"
    }
}

# In production, use a proper database
user_sessions = {}

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        
        if not username or not password:
            flash('Please enter both username and password')
            return redirect(url_for('login'))
            
        user = users.get(username)
        if not user or not check_password_hash(user['password_hash'], password):
            flash('Invalid username or password')
            return redirect(url_for('login'))
            
        # Generate session token
        session_token = secrets.token_urlsafe(32)
        session['session_token'] = session_token
        session['username'] = username
        session['mfa_verified'] = False
        
        # Store session info
        user_sessions[session_token] = {
            'username': username,
            'timestamp': datetime.now(),
            'mfa_verified': False
        }
        
        return redirect(url_for('verify_mfa'))
    
    return render_template_string('''
        <form method="post">
            <input type="text" name="username" placeholder="Username" required><br>
            <input type="password" name="password" placeholder="Password" required><br>
            <input type="submit" value="Login">
        </form>
    ''')

@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    if 'session_token' not in session:
        return redirect(url_for('login'))
        
    session_token = session['session_token']
    if session_token not in user_sessions:
        return redirect(url_for('login'))
        
    if session['mfa_verified']:
        return redirect(url_for('protected'))
        
    if request.method == 'POST':
        otp = request.form.get('otp')
        if not otp:
            flash('Please enter the OTP')
            return redirect(url_for('verify_mfa'))
            
        user = users.get(session['username'])
        totp = pyotp.TOTP(user['mfa_secret'])
        
        if totp.verify(otp, valid_window=2):
            user_sessions[session_token]['mfa_verified'] = True
            session['mfa_verified'] = True
            return redirect(url_for('protected'))
        else:
            flash('Invalid OTP')
            return redirect(url_for('verify_mfa'))
    
    # Generate QR code for MFA setup
    user = users.get(session['username'])
    totp_uri = pyotp.totp.TOTP(user['mfa_secret']).provisioning_uri(
        session['username'], issuer_name="MyApp"
    )
    
    qr = qrcode.QRCode(version=1, box_size=10, border=4)
    qr.add_data(totp_uri)
    qr.make(fit=True)
    
    img = qr.make_image(fill_color="black", back_color="white")
    img_buffer = io.BytesIO()
    img.save(img_buffer)
    img_buffer.seek(0)
    
    qr_code_data = img_buffer.getvalue()
    qr_code_b64 = qr_code_data.encode('base64').decode('utf-8')
    
    return render_template_string('''
        <h2>Two-Factor Authentication</h2>
        <p>Scan the QR code with your authenticator app:</p>
        <img src="data:image/png;base64,{{ qr_code_b64 }}" alt="QR Code"><br><br>
        <form method="post">
            <input type="text" name="otp" placeholder="Enter 6-digit OTP" required><br>
            <input type="submit" value="Verify">
        </form>
    ''', qr_code_b64=qr_code_b64)

@app.route('/protected')
def protected():
    if 'session_token' not in session or session.get('mfa_verified') is False:
        return redirect(url_for('login'))
        
    session_token = session['session_token']
    if session_token not in user_sessions or not user_sessions[session_token]['mfa_verified']:
        return redirect(url_for('login'))
        
    return f"Welcome {session['username']}! This is a protected resource."

# Background MFA verification
@app.before_request
def check_mfa():
    if request.endpoint and request.endpoint != 'login' and request.endpoint != 'verify_mfa':
        if 'session_token' in session:
            session_token = session['session_token']
            if session_token in user_sessions:
                # Check if session is expired (1 hour)
                if datetime.now() - user_sessions[session_token]['timestamp'] > timedelta(hours=1):
                    session.clear()
                    return redirect(url_for('login'))
                
                # Ensure MFA was verified
                if not user_sessions[session_token]['mfa_verified']:
                    session.clear()
                    return redirect(url_for('login'))

if __name__ == '__main__':
    app.run(debug=False)